+sealed class Notepad
+{
+    private readonly List<string> _notes = [];
+
+    [Description("Saves a research note. Use this to record key findings, facts, or quotes during research.")]
+    public string AddNote([Description("The note content to save")] string note)
+    {
+        _notes.Add(note);
+        Console.ForegroundColor = ConsoleColor.DarkYellow;
+        Console.WriteLine($"  📝  Note #{_notes.Count} saved ({note.Length} chars)");
+        Console.ResetColor();
+        return $"Note #{_notes.Count} saved successfully.";
+    }
+
+    [Description("Retrieves all saved research notes.")]
+    public string GetNotes()
+    {
+        if (_notes.Count == 0)
+            return "No notes have been saved yet.";
+
+        var sb = new StringBuilder();
+        sb.AppendLine($"Research notes ({_notes.Count} total):\n");
+        for (int i = 0; i < _notes.Count; i++)
+            sb.AppendLine($"[{i + 1}] {_notes[i]}\n");
+        return sb.ToString();
+    }
+
+    [Description("Clears all saved notes to start fresh.")]
+    public string ClearNotes()
+    {
+        _notes.Clear();
+        return "All notes cleared.";
+    }
+}

