 }

 // ---------------------------------------------------------------------------
 // Build the chat client with automatic function invocation
 // ---------------------------------------------------------------------------
 OpenAI.OpenAIClient openAIClient = endpoint is not null
     ? new(new System.ClientModel.ApiKeyCredential(apiKey), new OpenAI.OpenAIClientOptions { Endpoint = new Uri(endpoint) })
     : new(apiKey);

 IChatClient chatClient = openAIClient
     .GetChatClient(modelName)
     .AsIChatClient()
     .AsBuilder()
     .UseFunctionInvocation()
     .Build();

 // ---------------------------------------------------------------------------
 // Research tools
 // ---------------------------------------------------------------------------
 var notepad = new Notepad();
 var webSearcher = new WebSearcher();

 List<AITool> tools =
 [
     AIFunctionFactory.Create(webSearcher.SearchWeb),
     AIFunctionFactory.Create(webSearcher.ReadWebPage),
     AIFunctionFactory.Create(notepad.AddNote),
     AIFunctionFactory.Create(notepad.GetNotes),
     AIFunctionFactory.Create(notepad.ClearNotes),
 ];

 // ---------------------------------------------------------------------------
 // Create the AI agent
 // ---------------------------------------------------------------------------
 const string instructions = """
     You are a research agent. When the user gives you a topic:
     1. Search the web for relevant information using the SearchWeb tool.
     2. Read promising pages with ReadWebPage to get detailed content.
     3. Save key findings as notes using the AddNote tool.
     4. After gathering enough information (aim for at least 3-5 notes),
        retrieve all notes with GetNotes, then present a well-structured
        summary to the user.
     Be thorough but concise. Cite sources when possible.
     """;

 ChatClientAgent agent = chatClient.AsAIAgent(
     instructions: instructions,
     name: "ResearchAgent",
     description: "Researches topics by searching the web and summarizing findings");

 // ---------------------------------------------------------------------------
 // Interactive loop
 // ---------------------------------------------------------------------------
 Console.WriteLine("╔══════════════════════════════════════════╗");
 Console.WriteLine("║        AI Research Agent (.NET 10)       ║");
 Console.WriteLine("╠══════════════════════════════════════════╣");
 Console.WriteLine("║  Enter a topic to research, or 'quit'.  ║");
 Console.WriteLine("╚══════════════════════════════════════════╝");
 Console.WriteLine();

 while (true)
 {
     Console.ForegroundColor = ConsoleColor.Cyan;
     Console.Write("Research topic> ");
     Console.ResetColor();

     var topic = Console.ReadLine();
     if (string.IsNullOrWhiteSpace(topic))
         continue;
     if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase) ||
         topic.Equals("exit", StringComparison.OrdinalIgnoreCase))
         break;

     notepad.ClearNotes();

     Console.ForegroundColor = ConsoleColor.DarkGray;
     Console.WriteLine($"\nResearching \"{topic}\"...\n");
     Console.ResetColor();

     try
     {
         var session = await agent.CreateSessionAsync();
         var runOptions = new ChatClientAgentRunOptions(new ChatOptions { Tools = tools });
         var response = await agent.RunAsync(
             $"Research the following topic and provide a summary: {topic}",
             session,
             runOptions);

         Console.ForegroundColor = ConsoleColor.Green;
         Console.WriteLine("── Research Summary ─────────────────────────");
         Console.ResetColor();
         Console.WriteLine(response.Text);
         Console.WriteLine();
     }
     catch (Exception ex)
     {
         Console.ForegroundColor = ConsoleColor.Red;
         Console.WriteLine($"Error: {ex.Message}");
         Console.ResetColor();
     }
 }

 Console.WriteLine("Goodbye!");
 return 0;

 // ═══════════════════════════════════════════════════════════════════════════
 // Tool: Web Search
 // ═══════════════════════════════════════════════════════════════════════════
 sealed class WebSearcher
 {
     private readonly HttpClient _http = new()
     {
         DefaultRequestHeaders =
         {
             { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
             { "Accept", "text/html" },
         },
         Timeout = TimeSpan.FromSeconds(15),
     };

     [Description("Searches the web for the given query and returns a list of result titles, URLs, and snippets.")]
     public async Task<string> SearchWeb(
         [Description("The search query string")] string query,
         CancellationToken cancellationToken = default)
     {
         Console.ForegroundColor = ConsoleColor.DarkYellow;
         Console.WriteLine($"  🔍  Searching: \"{query}\"");
         Console.ResetColor();

         try
         {
             var encoded = Uri.EscapeDataString(query);
             var url = $"https://html.duckduckgo.com/html/?q={encoded}";

             var html = await _http.GetStringAsync(url, cancellationToken);
             var results = ParseSearchResults(html);

             if (results.Count == 0)
                 return "No search results found.";

             var sb = new StringBuilder();
             sb.AppendLine($"Search results for \"{query}\":\n");
             foreach (var (title, link, snippet) in results.Take(8))
             {
                 sb.AppendLine($"- **{title}**");
                 sb.AppendLine($"  URL: {link}");
                 sb.AppendLine($"  {snippet}");
                 sb.AppendLine();
             }

             return sb.ToString();
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}";
         }
     }

     [Description("Reads and extracts the main text content from a web page URL.")]
     public async Task<string> ReadWebPage(
         [Description("The full URL of the web page to read")] string url,
         CancellationToken cancellationToken = default)
     {
         Console.ForegroundColor = ConsoleColor.DarkYellow;
         Console.WriteLine($"  📄  Reading: {url}");
         Console.ResetColor();

         try
         {
             var html = await _http.GetStringAsync(url, cancellationToken);
             var text = ExtractTextFromHtml(html);

             // Truncate to avoid exceeding token limits
             const int maxLength = 4000;
             if (text.Length > maxLength)
                 text = text[..maxLength] + "\n\n[Content truncated...]";

             return string.IsNullOrWhiteSpace(text)
                 ? "Could not extract meaningful content from this page."
                 : $"Content from {url}:\n\n{text}";
         }
         catch (Exception ex)
         {
             return $"Failed to read page: {ex.Message}";
         }
     }

     private static List<(string Title, string Url, string Snippet)> ParseSearchResults(string html)
     {
         var results = new List<(string, string, string)>();

         // Parse DuckDuckGo HTML search results
         var resultPattern = new Regex(
             @"<a[^>]+class=""result__a""[^>]*href=""([^""]*?)""[^>]*>(.*?)</a>.*?<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
             RegexOptions.Singleline | RegexOptions.IgnoreCase);

         foreach (Match m in resultPattern.Matches(html))
         {
             var rawUrl = WebUtility.HtmlDecode(m.Groups[1].Value);
             var title = StripHtml(m.Groups[2].Value);
             var snippet = StripHtml(m.Groups[3].Value);

             // DuckDuckGo wraps URLs in a redirect; extract the real URL
             var udMatch = Regex.Match(rawUrl, @"[?&]uddg=([^&]+)");
             var actualUrl = udMatch.Success ? Uri.UnescapeDataString(udMatch.Groups[1].Value) : rawUrl;

             if (!string.IsNullOrWhiteSpace(title))
                 results.Add((title.Trim(), actualUrl.Trim(), snippet.Trim()));
         }

         return results;
     }

     private static string ExtractTextFromHtml(string html)
     {
         // Remove script, style, nav, header, footer blocks
         var cleaned = Regex.Replace(html, @"<(script|style|nav|header|footer|aside)[^>]*>.*?</\1>", " ",
             RegexOptions.Singleline | RegexOptions.IgnoreCase);
         // Remove all remaining tags
         cleaned = Regex.Replace(cleaned, @"<[^>]+>", " ");
         // Decode HTML entities
         cleaned = WebUtility.HtmlDecode(cleaned);
         // Collapse whitespace
         cleaned = Regex.Replace(cleaned, @"\s+", " ").Trim();
         return cleaned;
     }

     private static string StripHtml(string html) =>
         WebUtility.HtmlDecode(Regex.Replace(html, @"<[^>]+>", "")).Trim();
 }

 // ═══════════════════════════════════════════════════════════════════════════
 // Tool: Note-taking
 // ═══════════════════════════════════════════════════════════════════════════
 sealed class Notepad
 {
     private readonly List<string> _notes = [];

     [Description("Saves a research note. Use this to record key findings, facts, or quotes during research.")]
     public string AddNote([Description("The note content to save")] string note)
     {
         _notes.Add(note);
         Console.ForegroundColor = ConsoleColor.DarkYellow;
         Console.WriteLine($"  📝  Note #{_notes.Count} saved ({note.Length} chars)");
         Console.ResetColor();
         return $"Note #{_notes.Count} saved successfully.";
     }

     [Description("Retrieves all saved research notes.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes have been saved yet.";

         var sb = new StringBuilder();
         sb.AppendLine($"Research notes ({_notes.Count} total):\n");
         for (int i = 0; i < _notes.Count; i++)
             sb.AppendLine($"[{i + 1}] {_notes[i]}\n");
         return sb.ToString();
     }

     [Description("Clears all saved notes to start fresh.")]
     public string ClearNotes()
     {
         _notes.Clear();
         return "All notes cleared.";
     }
 }
